 55→/**
 56→ * This is a temporary class to make the PostListViewModel more manageable. Please feel free to refactor it any way
 57→ * you see fit.
 58→ */
 59→@Suppress("LongParameterList")
 60→class PostActionHandler(
 61→    private val dispatcher: Dispatcher,
 62→    private val site: SiteModel,
 63→    private val postStore: PostStore,
 64→    private val postListDialogHelper: PostListDialogHelper,
 65→    private val doesPostHaveUnhandledConflict: (PostModel) -> Boolean,
 66→    private val hasUnhandledAutoSave: (PostModel) -> Boolean,
 67→    private val triggerPostListAction: (PostListAction) -> Unit,
 68→    private val triggerPostUploadAction: (PostUploadAction) -> Unit,
 69→    private val triggerPublishAction: (PostModel) -> Unit,
 70→    private val invalidateList: () -> Unit,
 71→    private val checkNetworkConnection: () -> Boolean,
 72→    private val showSnackbar: (SnackbarMessageHolder) -> Unit,
 73→    private val showToast: (ToastMessageHolder) -> Unit,
 74→    private val triggerPreviewStateUpdate: (PostListRemotePreviewState, PostInfoType) -> Unit,
 75→    private val copyPost: (SiteModel, PostModel, Boolean) -> Unit
 76→) {
 77→    private val criticalPostActionTracker = CriticalPostActionTracker(onStateChanged = {
 78→        invalidateList.invoke()
 79→    })
 80→
 81→    fun handlePostButton(buttonType: PostListButtonType, post: PostModel, hasAutoSave: Boolean) {
 82→        when (buttonType) {
 83→            BUTTON_EDIT -> editPostButtonAction(site, post)
 84→            BUTTON_RETRY -> triggerPostListAction.invoke(RetryUpload(post))
 85→            BUTTON_MOVE_TO_DRAFT -> {
 86→                moveTrashedPostToDraft(post)
 87→            }
 88→            BUTTON_PUBLISH -> {
 89→                triggerPublishAction.invoke(post)
 90→            }
 91→            BUTTON_SYNC -> {
 92→                postListDialogHelper.showSyncScheduledPostConfirmationDialog(post)
 93→            }
 94→            BUTTON_SUBMIT -> publishPost(post.id)
 95→            BUTTON_VIEW -> triggerPostListAction.invoke(ViewPost(site, post))
 96→            BUTTON_PREVIEW -> triggerPostListAction.invoke(
 97→                PreviewPost(
 98→                    site = site,
 99→                    post = post,
100→                    triggerPreviewStateUpdate = triggerPreviewStateUpdate,
101→                    showToast = showToast,
102→                    messageMediaUploading = ToastMessageHolder(
103→                        R.string.editor_toast_uploading_please_wait,
104→                        Duration.SHORT
105→                    )
106→                )
107→            )
108→            BUTTON_STATS -> triggerPostListAction.invoke(ViewStats(site, post))
109→            BUTTON_TRASH -> {
110→                when {
111→                    post.isLocallyChanged -> {
112→                        postListDialogHelper.showTrashPostWithLocalChangesConfirmationDialog(post)
113→                    }
114→                    hasAutoSave -> {
115→                        postListDialogHelper.showTrashPostWithUnsavedChangesConfirmationDialog(post)
116→                    }
117→                    else -> trashPost(post)
118→                }
119→            }
120→            BUTTON_COPY -> copyPost(site, post, true)
121→            BUTTON_COPY_URL -> triggerPostListAction.invoke(copyUrlAction(post))
122→            BUTTON_DELETE, BUTTON_DELETE_PERMANENTLY -> {
123→                postListDialogHelper.showDeletePostConfirmationDialog(post)
124→            }
125→            BUTTON_CANCEL_PENDING_AUTO_UPLOAD -> {
126→                cancelPendingAutoUpload(post)
127→            }
128→            BUTTON_SHOW_MOVE_TRASHED_POST_TO_DRAFT_DIALOG -> {
129→                postListDialogHelper.showMoveTrashedPostToDraftDialog(post)
130→            }
131→            BUTTON_MORE -> {
132→            } // do nothing - ui will show a popup window
133→            BUTTON_PROMOTE_WITH_BLAZE -> {
134→                triggerPostListAction.invoke(PostListAction.ShowPromoteWithBlaze(post))
135→            }
136→        }
137→    }
138→
139→    private fun copyUrlAction(post: PostModel) = PostListAction.CopyUrl(
140→        site = site,
141→        post = post,
142→        showSnackbar = showSnackbar,
143→        messageSuccess = SnackbarMessageHolder(
144→            UiStringRes(R.string.post_link_copied_to_clipboard),
145→            duration = Snackbar.LENGTH_SHORT,
146→            isImportant = false
147→        ),
148→        messageError = SnackbarMessageHolder(
149→            UiStringRes(R.string.error_copy_to_clipboard),
150→            duration = Snackbar.LENGTH_SHORT,
151→            isImportant = false
152→        )
153→    )
154→
155→    private fun cancelPendingAutoUpload(post: PostModel) {
156→        val msgRes = UploadUtils.cancelPendingAutoUpload(post, dispatcher)
157→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(msgRes)))
158→    }
159→
160→    fun newPost() {
161→        triggerPostListAction(PostListAction.NewPost(site))
162→    }
163→
164→    fun newStoryPost() {
165→        triggerPostListAction(PostListAction.NewStoryPost(site))
166→    }
167→
168→    fun handleEditPostResult(data: Intent?) {
169→        val localPostId = data?.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0)
170→        if (localPostId == null || localPostId == 0) {
171→            return
172→        }
173→        val post = postStore.getPostByLocalPostId(localPostId)
174→        if (post != null) {
175→            triggerPostUploadAction(EditPostResult(site, post, data) { publishPost(localPostId) })
176→        }
177→    }
178→
179→    fun handleRemotePreview(localPostId: Int, remotePreviewType: RemotePreviewType) {
180→        val post = postStore.getPostByLocalPostId(localPostId)
181→        if (post != null) {
182→            triggerPostListAction.invoke(PostListAction.RemotePreviewPost(site, post, remotePreviewType))
183→        }
184→    }
185→
186→    fun publishPost(localPostId: Int) {
187→        val post = postStore.getPostByLocalPostId(localPostId)
188→        if (post != null) {
189→            triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
190→        }
191→    }
192→
193→    fun publishPost(post: PostModel) {
194→        triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
195→    }
196→
197→    fun resolveConflictsAndEditPost(localPostId: Int) {
198→        val post = postStore.getPostByLocalPostId(localPostId)
199→        if (post != null) {
200→            performChecksAndEdit(site, post)
201→        }
202→    }
203→
204→    fun moveTrashedPostToDraft(localPostId: Int) {
205→        val post = postStore.getPostByLocalPostId(localPostId)
206→        if (post != null) {
207→            moveTrashedPostToDraft(post)
208→        }
209→    }
210→
211→    private fun moveTrashedPostToDraft(post: PostModel) {
212→        /*
213→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
214→         * but that'll leave the trashed post in the remote which can be confusing.
215→         */
216→        if (!checkNetworkConnection.invoke()) {
217→            return
218→        }
219→        post.setStatus(DRAFT.toString())
220→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
221→
222→        val localPostId = LocalId(post.id)
223→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
224→
225→        val snackBarHolder = SnackbarMessageHolder(
226→            message = UiStringRes(R.string.post_moving_to_draft),
227→            onDismissAction = {
228→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
229→            }
230→        )
231→        showSnackbar.invoke(snackBarHolder)
232→    }
233→
234→    private fun editPostButtonAction(site: SiteModel, post: PostModel) = performChecksAndEdit(site, post)
235→
236→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
237→        // first of all, check whether this post is in Conflicted state with a more recent remote version
238→        if (doesPostHaveUnhandledConflict.invoke(post)) {
239→            postListDialogHelper.showConflictedPostResolutionDialog(post)
240→            return
241→        }
242→
243→        // Then check if an autosave revision is available
244→        if (hasUnhandledAutoSave.invoke(post)) {
245→            postListDialogHelper.showAutoSaveRevisionDialog(post)
246→            return
247→        }
248→
249→        editPost(site, post)
250→    }
251→
252→    private fun editPost(site: SiteModel, post: PostModel) {
253→        if (UploadService.isPostUploadingOrQueued(post)) {
254→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
255→            // post itself when they finish (since we're about to edit it again)
256→            UploadService.cancelQueuedPostUpload(post)
257→        }
258→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
259→    }
260→
261→    fun deletePost(localPostId: Int) {
262→        // If post doesn't exist, nothing else to do
263→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
264→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
265→
266→        when {
267→            post.isLocalDraft -> {
268→                val pushId = PendingDraftsNotificationsUtils.makePendingDraftNotificationId(post.id)
269→                triggerPostListAction(DismissPendingNotification(pushId))
270→                dispatcher.dispatch(PostActionBuilder.newRemovePostAction(post))
271→            }
272→            else -> {
273→                dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
274→            }
275→        }
276→    }
277→
278→    /**
279→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
280→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
281→     *
282→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
283→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
284→     * expectations clearer.
285→     */
286→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
287→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
288→            /*
289→             * This is an unexpected action and either it has already been handled or another critical action has
290→             * been performed. In either case, safest action is to just ignore it.
291→             */
292→            return
293→        }
294→        if (isError) {
295→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
296→        }
297→        if (isRemoved) {
298→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
299→        }
300→    }
301→
302→    fun trashPostWithLocalChanges(localPostId: Int) {
303→        // If post doesn't exist, nothing else to do
304→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
305→        trashPost(post, true)
306→    }
307→
308→    fun trashPostWithUnsavedChanges(localPostId: Int) {
309→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
310→        trashPost(post)
311→    }
312→
313→    private fun trashPost(post: PostModel, hasLocalChanges: Boolean = false) {
314→        // We need network connection to trash a post
315→        if (!checkNetworkConnection()) {
316→            return
317→        }
318→        val criticalPostAction = if (hasLocalChanges) {
319→            TRASHING_POST_WITH_LOCAL_CHANGES
320→        } else {
321→            TRASHING_POST
322→        }
323→
324→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(R.string.post_trashing)))
325→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = criticalPostAction)
326→
327→        triggerPostUploadAction.invoke(CancelPostAndMediaUpload(post))
328→        dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
329→    }
330→
331→    @Suppress("UseCheckOrError")
332→    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
333→        val criticalAction = criticalPostActionTracker.get(localPostId)
334→        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
335→            /*
336→             * This is an unexpected action and either it has already been handled or another critical action has
337→             * been performed. In either case, safest action is to just ignore it.
338→             */
339→            return
340→        }
341→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
342→        if (isError) {
343→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
344→        } else {
345→            val snackBarHolder = when (criticalAction) {
346→                TRASHING_POST -> SnackbarMessageHolder(
347→                    message = UiStringRes(R.string.post_trashed),
348→                    buttonTitle = UiStringRes(R.string.undo),
349→                    buttonAction = {
350→                        val post = postStore.getPostByLocalPostId(localPostId.value)
351→                        if (post != null) {
352→                            restorePost(post)
353→                        }
354→                    }
355→                )
356→                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
357→                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
358→            }
359→            showSnackbar.invoke(snackBarHolder)
360→        }
361→    }
362→
363→    private fun restorePost(post: PostModel) {
364→        // We need network connection to restore a post
365→        if (!checkNetworkConnection.invoke()) {
366→            return
367→        }
368→        showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restoring)))
369→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = RESTORING_POST)
370→        dispatcher.dispatch(PostActionBuilder.newRestorePostAction(RemotePostPayload(post, site)))
371→    }
372→
373→    fun handlePostRestored(localPostId: LocalId, isError: Boolean) {
374→        if (criticalPostActionTracker.get(localPostId) != RESTORING_POST) {
375→            /*
376→             * This is an unexpected action and either it has already been handled or another critical action has
377→             * been performed. In either case, safest action is to just ignore it.
378→             */
379→            return
380→        }
381→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = RESTORING_POST)
382→        if (isError) {
383→            showToast.invoke(ToastMessageHolder(R.string.error_restoring_post, Duration.SHORT))
384→        } else {
385→            showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restored)))
386→        }
387→    }
388→
389→    fun isPerformingCriticalAction(localPostId: LocalId): Boolean {
390→        return criticalPostActionTracker.contains(localPostId)
391→    }
392→}
