","new_string":"    @Suppress("LongParameterList", "ComplexMethod")
    private fun createButtonTypes(
        postStatus: PostStatus,
        isLocalDraft: Boolean,
        isLocallyChanged: Boolean,
        uploadUiState: PostUploadUiState,
        siteHasCapabilitiesToPublish: Boolean,
        statsSupported: Boolean,
        shouldShowStatsInJetpackRemovalPhase: Boolean,
        shouldShowPromoteWithBlaze: Boolean
    ): List<PostListButtonType> {
        val canRetryUpload = uploadUiState is UploadFailed
        val canCancelPendingAutoUpload = uploadUiState is UploadWaitingForConnection ||
                (uploadUiState is UploadFailed && uploadUiState.isEligibleForAutoUpload)
        if (postStatus == TRASHED) {
            return listOf(BUTTON_MOVE_TO_DRAFT, BUTTON_DELETE_PERMANENTLY)
        }

        val canShowStats = statsSupported &&
                postStatus == PUBLISHED &&
                !isLocalDraft &&
                !isLocallyChanged &&
                shouldShowStatsInJetpackRemovalPhase
        val canShowCopy = postStatus == PUBLISHED || postStatus == DRAFT
        val canShowCopyUrlButton = !isLocalDraft && postStatus != TRASHED
        val canShowViewButton = !canRetryUpload && postStatus != TRASHED

        val buttonTypes = mutableListOf<PostListButtonType>()
        buttonTypes.add(BUTTON_EDIT)

        getPublishAction(
            canRetryUpload = canRetryUpload,
            uploadUiState = uploadUiState,
            canCancelPendingAutoUpload = canCancelPendingAutoUpload,
            isLocalDraft = isLocalDraft,
            isLocallyChanged = isLocallyChanged,
            postStatus = postStatus,
            siteHasCapabilitiesToPublish = siteHasCapabilitiesToPublish
        )?.let { buttonTypes.add(it) }

        getViewOrPreviewAction(
            canShowViewButton = canShowViewButton,
            shouldShowPreview = isLocalDraft || isLocallyChanged
        )?.let { buttonTypes.add(it) }

        if (canShowStats) {
            buttonTypes.add(BUTTON_STATS)
        }

        buttonTypes.addAll(getOfflineActions(canCancelPendingAutoUpload, canRetryUpload))
        buttonTypes.addAll(
            getShareAndPromoteActions(
                canShowCopyUrlButton = canShowCopyUrlButton,
                canShowCopy = canShowCopy,
                shouldShowPromoteWithBlaze = shouldShowPromoteWithBlaze
            )
        )
        buttonTypes.addAll(getManageActions(isLocalDraft, postStatus))

        return buttonTypes
    }

    private fun getPublishAction(
        canRetryUpload: Boolean,
        uploadUiState: PostUploadUiState,
        canCancelPendingAutoUpload: Boolean,
        isLocalDraft: Boolean,
        isLocallyChanged: Boolean,
        postStatus: PostStatus,
        siteHasCapabilitiesToPublish: Boolean
    ): PostListButtonType? {
        if (canRetryUpload) {
            return null
        }
        val shouldShowPublishAction =
            (uploadUiState is NothingToUpload || !canCancelPendingAutoUpload) &&
                    (isLocallyChanged || isLocalDraft || postStatus == DRAFT ||
                            (siteHasCapabilitiesToPublish && postStatus == PENDING))
        if (!shouldShowPublishAction) {
            return null
        }
        return when {
            !siteHasCapabilitiesToPublish -> BUTTON_SUBMIT
            postStatus == SCHEDULED && isLocallyChanged -> BUTTON_SYNC
            else -> BUTTON_PUBLISH
        }
    }

    private fun getViewOrPreviewAction(
        canShowViewButton: Boolean,
        shouldShowPreview: Boolean
    ): PostListButtonType? {
        if (!canShowViewButton) {
            return null
        }
        return if (shouldShowPreview) BUTTON_PREVIEW else BUTTON_VIEW
    }

    private fun getOfflineActions(
        canCancelPendingAutoUpload: Boolean,
        canRetryUpload: Boolean
    ): List<PostListButtonType> {
        val offlineActions = mutableListOf<PostListButtonType>()
        if (canCancelPendingAutoUpload) {
            offlineActions.add(BUTTON_CANCEL_PENDING_AUTO_UPLOAD)
        }
        if (canRetryUpload) {
            offlineActions.add(BUTTON_RETRY)
        }
        return offlineActions
    }

    private fun getShareAndPromoteActions(
        canShowCopyUrlButton: Boolean,
        canShowCopy: Boolean,
        shouldShowPromoteWithBlaze: Boolean
    ): List<PostListButtonType> {
        val shareActions = mutableListOf<PostListButtonType>()
        if (canShowCopyUrlButton) {
            shareActions.add(BUTTON_COPY_URL)
        }
        if (canShowCopy) {
            shareActions.add(BUTTON_COPY)
        }
        if (shouldShowPromoteWithBlaze) {
            shareActions.add(BUTTON_PROMOTE_WITH_BLAZE)
        }
        return shareActions
    }

    private fun getManageActions(
        isLocalDraft: Boolean,
        postStatus: PostStatus
    ): List<PostListButtonType> {
        val manageActions = mutableListOf<PostListButtonType>()
        if (postStatus == PUBLISHED) {
            manageActions.add(BUTTON_MOVE_TO_DRAFT)
        }
        manageActions.add(
            if (isLocalDraft) {
                BUTTON_DELETE
            } else {
                BUTTON_TRASH
            }
        )
        return manageActions
    }
