236→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
237→        // first of all, check whether this post is in Conflicted state with a more recent remote version
238→        if (doesPostHaveUnhandledConflict.invoke(post)) {
239→            postListDialogHelper.showConflictedPostResolutionDialog(post)
240→            return
241→        }
242→
243→        // Then check if an autosave revision is available
244→        if (hasUnhandledAutoSave.invoke(post)) {
245→            postListDialogHelper.showAutoSaveRevisionDialog(post)
246→            return
247→        }
248→
249→        editPost(site, post)
250→    }
